qry:select.qry:xquery:
				for $r in SQL('
SELECT 
PER02_PERSONAL_EMP.oi_personal_emp, 
PER01_PERSONAL.d_ape_y_nom, 
PER02_PERSONAL_EMP.e_numero_legajo
FROM
PER01_PERSONAL, PER02_PERSONAL_EMP
JOIN
PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal
WHERE    
PER02_PERSONAL_EMP.oi_empresa = {#PARAM:@oi_empresa}
{%? (#PARAMIN:@oi_personal_emp!='') 
	{% AND PER02_PERSONAL_EMP.oi_personal_emp = {#PARAMIN:@oi_personal_emp} %}
	{% 
	{%? (#PARAMIN:@l_incluir!='1') 
	{% AND PER02_PERSONAL_EMP.oi_indic_activo = 1 %}
	{% %} 
%}
	%} 
%}

{%? (#PARAMIN:@cb_confidenciales != '' and #PARAMIN:@cb_confidenciales!='T' ) 
{%  
{%? (#PARAMIN:@cb_confidenciales = 'C') {%	AND PER02_PERSONAL_EMP.l_confidencial = 1%}{% AND PER02_PERSONAL_EMP.l_confidencial = 0 %} %} 
%} 
{%	%}
%}


ORDER BY 
e_numero_legajo asc
')/ROWS
